   248→    match categories {
   249→        SegmentOptionCategories {
   250→            type_: None | Some(Int { .. }),
   251→            ..
   252→        } => {}
   253→
   254→        SegmentOptionCategories {
   255→            type_: Some(opt),
   256→            signed: Some(sign),
   257→            ..
   258→        } => {
   259→            return err(
   260→                ErrorType::SignednessUsedOnNonInt { type_: opt.label() },
   261→                sign.location(),
   262→            );
   263→        }
   264→
   265→        _ => {}
   266→    }
