fn expect_bit_array_pattern_segment_size_expr(&mut self) -> Result<UntypedPattern, ParseError> {
    // Parse using the guard expression parser, then convert to a pattern-compatible form
    // We'll parse expressions with operator precedence
    let mut opstack = vec![];
    let mut estack = vec![];
    let mut last_op_start = 0;
    let mut last_op_end = 0;

    loop {
        match self.parse_bit_array_pattern_segment_size_unit()? {
            Some(unit) => estack.push(unit),
            _ => {
                if estack.is_empty() {
                    return self.next_tok_unexpected(vec!["A variable name, integer, or expression".into()]);
                } else if !opstack.is_empty() {
                    return parse_error(
                        ParseErrorType::OpNakedRight,
                        SrcSpan {
                            start: last_op_start,
                            end: last_op_end,
                        },
                    );
                } else {
                    break;
                }
            }
        }

        if let Some((op_s, t, op_e)) = self.tok0 {
            // Check if this is an arithmetic operator valid in guards
            match &t {
                Token::Plus | Token::Minus | Token::Star | Token::Slash | Token::Percent => {
                    self.advance();
                    last_op_start = op_s;
                    last_op_end = op_e;
                    opstack.push((op_s, t, op_e));
                }
                _ => {
                    // Not an operator, stop parsing
                    break;
                }
            }
        } else {
            break;
        }
    }

    // Reduce the expression stack with operators
    while let Some((op_s, op, op_e)) = opstack.pop() {
        if estack.len() < 2 {
            return parse_error(
                ParseErrorType::OpNakedRight,
                SrcSpan {
                    start: op_s,
                    end: op_e,
                },
            );
        }
        let right = estack.pop().unwrap();
        let left = estack.pop().unwrap();
        let combined = self.combine_pattern_size_operands(left, op, right, op_s, op_e)?;
        estack.push(combined);
    }

    if estack.len() != 1 {
        return parse_error(
            ParseErrorType::ExpectedValue,
            SrcSpan { start: 0, end: 0 },
        );
    }

    Ok(estack.pop().unwrap())
}

fn parse_bit_array_pattern_segment_size_unit(&mut self) -> Result<Option<UntypedPattern>, ParseError> {
    match self.tok0 {
        Some((start, Token::Name { name }, end)) => {
            self.advance();
            Ok(Some(Pattern::VarUsage {
                location: SrcSpan { start, end },
                name: name.clone(),
                constructor: None,
                type_: (),
            }))
        }
        Some((start, Token::Int { value, int_value }, end)) => {
            self.advance();
            Ok(Some(Pattern::Int {
                location: SrcSpan { start, end },
                value: value.clone(),
                int_value: int_value.clone(),
            }))
        }
        Some((start, Token::LeftParen, _)) => {
            self.advance();
            let inner = self.expect_bit_array_pattern_segment_size_expr()?;
            self.expect_one(&Token::RightParen)?;
            Ok(Some(inner))
        }
        _ => Ok(None),
    }
}

