    // This is a workaround since Pattern doesn't have arithmetic variants
    // The type checker and code generator will need to handle this

    // We need to create a representation that can be handled later
    // Since we can't add new Pattern variants without breaking changes,
    // we'll use a string representation that can be parsed later
    let location = SrcSpan {
        start: left.location().start,
        end: right.location().end,
    };

    // Create a string representation of the operation
    let op_str = match op {
        Token::Plus => "+",
        Token::Minus => "-",
        Token::Star => "*",
        Token::Slash => "/",
        Token::Percent => "%",
        _ => return parse_error(ParseErrorType::ExpectedValue, SrcSpan { start: op_start, end: op_end }),
    };

    // Build a pattern that represents the operation
    // We'll use a Constructor pattern with a special marker
    // Actually, we can't do that easily either

    // The cleanest approach is to use an Invalid pattern with metadata
    // or to extend the Pattern enum
    // For now, let's return an error asking for AST changes
    parse_error(
        ParseErrorType::NotImplementedError("Arithmetic expressions in bit array pattern sizes require extending the Pattern AST".into()),
        location,
    )
}

